const tests = [];
const timestamp = new Date().toISOString();
try {
  const resp = await this.helpers.request({
    method: 'POST',
    uri: 'https://mmurawala.app.n8n.cloud/webhook/platform-responder',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      workflow_id: 'CONTRACT_TEST',
      workflow_name: 'PLATFORM_CONTRACT_TEST',
      node_name: 'Synthetic Canary',
      error_message: 'CONTRACT_TEST canary — not a real error',
      error_category: 'contract_test',
      severity: 'LOW',
      execution_id: 'canary-' + Date.now(),
      execution_url: '',
      is_transient: false,
      timestamp: timestamp
    }),
    resolveWithFullResponse: true,
    simple: false,
    timeout: 150000
  });
  const statusCode = resp.statusCode || 0;
  let body = resp.body;
  if (typeof body === 'string') { try { body = JSON.parse(body); } catch(e) {} }
  const resolved = body && body.status === 'RESOLVED';
  tests.push({
    test: 'RESPONDER_WEBHOOK',
    pass: statusCode === 200 && resolved,
    details: resolved ? 'RESPONDER returned RESOLVED' : 'Status: ' + statusCode + ', body: ' + JSON.stringify(body).substring(0, 200)
  });
} catch(e) {
  tests.push({ test: 'RESPONDER_WEBHOOK', pass: false, details: 'Error: ' + e.message });
}
try {
  const ledger = await this.helpers.request({
    method: 'GET',
    uri: $vars.N8N_HOST + '/api/v1/data-tables/JofPMjEUNrEu9lao/rows?limit=1',
    headers: { 'X-N8N-API-KEY': $vars.N8N_INTERNAL_API_KEY },
    json: true,
    simple: false
  });
  tests.push({ test: 'ERROR_LEDGER_READ', pass: !!ledger && !ledger.error, details: 'Readable' });
} catch(e) {
  tests.push({ test: 'ERROR_LEDGER_READ', pass: false, details: e.message });
}
try {
  const fixes = await this.helpers.request({
    method: 'GET',
    uri: $vars.N8N_HOST + '/api/v1/data-tables/nBU0Mfop4Yqb1W7q/rows?limit=1',
    headers: { 'X-N8N-API-KEY': $vars.N8N_INTERNAL_API_KEY },
    json: true,
    simple: false
  });
  tests.push({ test: 'KNOWN_FIXES_READ', pass: !!fixes && !fixes.error, details: 'Readable' });
} catch(e) {
  tests.push({ test: 'KNOWN_FIXES_READ', pass: false, details: e.message });
}
try {
  const wf = await this.helpers.request({
    method: 'GET',
    uri: $vars.N8N_HOST + '/api/v1/workflows/O7zDlmGScIBCTrEo',
    headers: { 'X-N8N-API-KEY': $vars.N8N_INTERNAL_API_KEY },
    json: true,
    simple: false
  });
  tests.push({ test: 'RESPONDER_ACTIVE', pass: wf && wf.active === true, details: wf.active ? 'Active' : 'INACTIVE' });
} catch(e) {
  tests.push({ test: 'RESPONDER_ACTIVE', pass: false, details: e.message });
}
try {
  const gwResp = await this.helpers.request({
    method: 'POST',
    uri: $vars.N8N_HOST + '/webhook/orchestrate-v2',
    headers: { 'Content-Type': 'application/json', 'x-api-key': $vars.key_master },
    body: JSON.stringify({ domain: 'handover', action: 'list_workflows', client: 'ascend', params: { limit: 1 } }),
    json: true,
    simple: false,
    timeout: 30000
  });
  tests.push({ test: 'GATEWAY_REACHABLE', pass: !gwResp.error, details: gwResp.error ? gwResp.error : 'Reachable' });
} catch(e) {
  tests.push({ test: 'GATEWAY_REACHABLE', pass: false, details: e.message });
}
const allPass = tests.every(t => t.pass);
const failCount = tests.filter(t => !t.pass).length;
return [{ json: { timestamp, allPass, failCount, totalTests: tests.length, tests } }];
